import re, unicodedata, difflib, math, numpy as np

AR_DIACRITICS = re.compile(r"[\u064B-\u0652\u0670\u0653-\u065F]")
TATWEEL = "\u0640"

def normalize_ar(s):
    if s is None:
        return ""
    s = s.replace(TATWEEL, "")
    s = AR_DIACRITICS.sub("", s)
    # unify hamza forms: أإآٱ to ا ; ؤ to و ; ئ to ي maybe; but we can map to bare forms
    s = s.replace("أ","ا").replace("إ","ا").replace("آ","ا").replace("ٱ","ا")
    s = s.replace("ؤ","و").replace("ئ","ي")
    # remove punctuation/ellipses
    s = re.sub(r"[^\w\s\u0621-\u064A]", " ", s)  # keep arabic letters, digits? remove punctuation
    s = re.sub(r"\s+", " ", s).strip()
    return s

def tokens(s):
    return normalize_ar(s).split()

def lcs_length(a, b):
    # char-level LCS; simple DP
    a_n = normalize_ar(a)
    b_n = normalize_ar(b)
    n, m = len(a_n), len(b_n)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            temp = dp[j]
            if a_n[i-1] == b_n[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = temp
    return dp[m]

def lcs_ratio(a,b):
    l = lcs_length(a,b)
    denom = max(len(normalize_ar(a)), len(normalize_ar(b)), 1)
    return l/denom

def token_f1(a,b):
    ta = tokens(a)
    tb = tokens(b)
    if not ta or not tb:
        return 0.0
    inter = 0
    tb_counts = {}
    for t in tb:
        tb_counts[t] = tb_counts.get(t,0)+1
    for t in ta:
        if tb_counts.get(t,0)>0:
            inter += 1
            tb_counts[t]-=1
    prec = inter/len(ta)
    rec = inter/len(tb)
    if prec+rec==0: return 0.0
    return 2*prec*rec/(prec+rec)

def difflib_ratio(a,b):
    return difflib.SequenceMatcher(None, normalize_ar(a), normalize_ar(b)).ratio()

def robust_sim(a,b):
    return max(lcs_ratio(a,b), difflib_ratio(a,b), token_f1(a,b))

